"""
Parameterized generator for GH60_starlette_3148.

Source PR:    https://github.com/Kludex/starlette/pull/3148
Source Issue: https://github.com/Kludex/starlette/issues/3146

Seed varies: renames 'abstract' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH60_starlette_3148'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH60_starlette_3148'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('abstract', 'abstract' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH60_starlette_3148',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'Kludex/starlette',
                "pr_number": 3148,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/Kludex/starlette/pull/3148",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'docs/templates.md': 'Starlette is not _strictly_ coupled to any particular templating engine, but\nJinja2 provides an excellent choice.\n\n### Jinja2Templates\n\nSignature: `Jinja2Templates(directory, context_processors=None, **env_options)`\n\n* `directory` - A string, [os.Pathlike][pathlike] or a list of strings or [os.Pathlike][pathlike] denoting a directory path.\n* `context_processors` - A list of functions that return a dictionary to add to the template context.\n* `**env_options` - Additional keyword arguments to pass to the Jinja2 environment.\n\nStarlette provides a simple way to get `jinja2` configured. This is probably\nwhat you want to use by default.\n\n```python\nfrom starlette.applications import Starlette\nfrom starlette.routing import Route, Mount\nfrom starlette.templating import Jinja2Templates\nfrom starlette.staticfiles import StaticFiles\n\n\ntemplates = Jinja2Templates(directory=\'templates\')\n\nasync def homepage(request):\n    return templates.TemplateResponse(request, \'index.html\')\n\nroutes = [\n    Route(\'/\', endpoint=homepage),\n    Mount(\'/static\', StaticFiles(directory=\'static\'), name=\'static\')\n]\n\napp = Starlette(debug=True, routes=routes)\n```\n\nNote that the incoming `request` instance must be included as part of the\ntemplate context.\n\nThe Jinja2 template context will automatically include a `url_for` function,\nso we can correctly hyperlink to other pages within the application.\n\nFor example, we can link to static files from within our HTML templates:\n\n```html\n<link href="{{ url_for(\'static\', path=\'/css/bootstrap.min.css\') }}" rel="stylesheet" />\n```\n\nIf you want to use [custom filters][jinja2], you will need to update the `env`\nproperty of `Jinja2Templates`:\n\n```python\nfrom commonmark import commonmark\nfrom starlette.templating import Jinja2Templates\n\ndef marked_filter(text):\n    return commonmark(text)\n\ntemplates = Jinja2Templates(directory=\'templates\')\ntemplates.env.filters[\'marked\'] = marked_filter\n```\n\n\n## Using custom jinja2.Environment instance\n\nStarlette also accepts a preconfigured [`jinja2.Environment`](https://jinja.palletsprojects.com/en/3.0.x/api/#api) instance. \n\n\n```python\nimport jinja2\nfrom starlette.templating import Jinja2Templates\n\nenv = jinja2.Environment(...)\ntemplates = Jinja2Templates(env=env)\n```\n\n\n## Context processors\n\nA context processor is a function that returns a dictionary to be merged into a template context.\nEvery function takes only one argument `request` and must return a dictionary to add to the context.\n\nA common use case of template processors is to extend the template context with shared variables.\n\n```python\nimport typing\nfrom starlette.requests import Request\n\ndef app_context(request: Request) -> typing.Dict[str, typing.Any]:\n    return {\'app\': request.app}\n```\n\n### Registering context templates\n\nPass context processors to `context_processors` argument of the `Jinja2Templates` class.\n\n```python\nimport typing\n\nfrom starlette.requests import Request\nfrom starlette.templating import Jinja2Templates\n\ndef app_context(request: Request) -> typing.Dict[str, typing.Any]:\n    return {\'app\': request.app}\n\ntemplates = Jinja2Templates(\n    directory=\'templates\', context_processors=[app_context]\n)\n```\n\n!!! info\n    Asynchronous functions as context processors are not supported.\n\n## Testing template responses\n\nWhen using the test client, template responses include `.template` and `.context`\nattributes.\n\n```python\nfrom starlette.testclient import TestClient\n\n\ndef test_homepage():\n    client = TestClient(app)\n    response = client.get("/")\n    assert response.status_code == 200\n    assert response.template.name == \'index.html\'\n    assert "request" in response.context\n```\n\n## Customizing Jinja2 Environment\n\n`Jinja2Templates` accepts all options supported by Jinja2 `Environment`.\nThis will allow more control over the `Environment` instance created by Starlette.\n\nFor the list of options available to `Environment` you can check Jinja2 documentation [here](https://jinja.palletsprojects.com/en/3.0.x/api/#jinja2.Environment)\n\n```python\nfrom starlette.templating import Jinja2Templates\n\n\ntemplates = Jinja2Templates(directory=\'templates\', autoescape=False, auto_reload=True)\n```\n\n## Asynchronous template rendering\n\nJinja2 supports async template rendering, however as a general rule\nwe\'d recommend that you keep your templates free from logic that invokes\ndatabase lookups, or other I/O operations.\n\nInstead we\'d recommend that you ensure that your endpoints perform all I/O,\nfor example, strictly evaluate any database queries within the view and\ninclude the final results in the context.\n\n[jinja2]: https://jinja.palletsprojects.com/en/3.0.x/api/?highlight=environment#writing-filters\n[pathlike]: https://docs.python.org/3/library/os.html#os.PathLike\n',
            'starlette/templating.py': 'from __future__ import annotations\n\nfrom collections.abc import Callable, Mapping, Sequence\nfrom os import PathLike\nfrom typing import TYPE_CHECKING, Any, overload\n\nfrom starlette.background import BackgroundTask\nfrom starlette.datastructures import URL\nfrom starlette.requests import Request\nfrom starlette.responses import HTMLResponse\nfrom starlette.types import Receive, Scope, Send\n\ntry:\n    import jinja2\n\n    # @contextfunction was renamed to @pass_context in Jinja 3.0, and was removed in 3.1\n    # hence we try to get pass_context (most installs will be >=3.1)\n    # and fall back to contextfunction,\n    # adding a type ignore for mypy to let us access an attribute that may not exist\n    if TYPE_CHECKING:\n        pass_context = jinja2.pass_context\n    else:\n        if hasattr(jinja2, "pass_context"):\n            pass_context = jinja2.pass_context\n        else:  # pragma: no cover\n            pass_context = jinja2.contextfunction  # type: ignore[attr-defined]\nexcept ImportError as _import_error:  # pragma: no cover\n    raise ImportError("jinja2 must be installed to use Jinja2Templates") from _import_error\n\n\nclass _TemplateResponse(HTMLResponse):\n    def __init__(\n        self,\n        template: Any,\n        context: dict[str, Any],\n        status_code: int = 200,\n        headers: Mapping[str, str] | None = None,\n        media_type: str | None = None,\n        background: BackgroundTask | None = None,\n    ):\n        self.template = template\n        self.context = context\n        content = template.render(context)\n        super().__init__(content, status_code, headers, media_type, background)\n\n    async def __call__(self, scope: Scope, receive: Receive, send: Send) -> None:\n        request = self.context.get("request", {})\n        extensions = request.get("extensions", {})\n        if "http.response.debug" in extensions:  # pragma: no branch\n            await send({"type": "http.response.debug", "info": {"template": self.template, "context": self.context}})\n        await super().__call__(scope, receive, send)\n\n\nclass Jinja2Templates:\n    """Jinja2 template renderer.\n\n    Example:\n        ```python\n        from starlette.templating import Jinja2Templates\n\n        templates = Jinja2Templates(directory="templates")\n\n        async def homepage(request: Request) -> Response:\n            return templates.TemplateResponse(request, "index.html")\n        ```\n    """\n\n    @overload\n    def __init__(\n        self,\n        directory: str | PathLike[str] | Sequence[str | PathLike[str]],\n        *,\n        context_processors: list[Callable[[Request], dict[str, Any]]] | None = None,\n    ) -> None: ...\n\n    @overload\n    def __init__(\n        self,\n        *,\n        env: jinja2.Environment,\n        context_processors: list[Callable[[Request], dict[str, Any]]] | None = None,\n    ) -> None: ...\n\n    def __init__(\n        self,\n        directory: str | PathLike[str] | Sequence[str | PathLike[str]] | None = None,\n        *,\n        context_processors: list[Callable[[Request], dict[str, Any]]] | None = None,\n        env: jinja2.Environment | None = None,\n    ) -> None:\n        assert bool(directory) ^ bool(env), "either \'directory\' or \'env\' arguments must be passed"\n        self.context_processors = context_processors or []\n        if directory is not None:\n            loader = jinja2.FileSystemLoader(directory)\n            self.env = jinja2.Environment(loader=loader)\n        elif env is not None:  # pragma: no branch\n            self.env = env\n\n        self._setup_env_defaults(self.env)\n\n    def _setup_env_defaults(self, env: jinja2.Environment) -> None:\n        @pass_context\n        def url_for(\n            context: dict[str, Any],\n            name: str,\n            /,\n            **path_params: Any,\n        ) -> URL:\n            request: Request = context["request"]\n            return request.url_for(name, **path_params)\n\n        env.globals.setdefault("url_for", url_for)\n\n    def get_template(self, name: str) -> jinja2.Template:\n        return self.env.get_template(name)\n\n    def TemplateResponse(\n        self,\n        request: Request,\n        name: str,\n        context: dict[str, Any] | None = None,\n        status_code: int = 200,\n        headers: Mapping[str, str] | None = None,\n        media_type: str | None = None,\n        background: BackgroundTask | None = None,\n    ) -> _TemplateResponse:\n        """\n        Render a template and return an HTML response.\n\n        Args:\n            request: The incoming request instance.\n            name: The template file name to render.\n            context: Variables to pass to the template.\n            status_code: HTTP status code for the response.\n            headers: Additional headers to include in the response.\n            media_type: Media type for the response.\n            background: Background task to run after response is sent.\n\n        Returns:\n            An HTML response with the rendered template content.\n        """\n        context = context or {}\n\n        context.setdefault("request", request)\n        for context_processor in self.context_processors:\n            context.update(context_processor(request))\n\n        template = self.get_template(name)\n        return _TemplateResponse(\n            template,\n            context,\n            status_code=status_code,\n            headers=headers,\n            media_type=media_type,\n            background=background,\n        )\n',
            'tests/test_templates.py': 'from __future__ import annotations\n\nimport os\nfrom pathlib import Path\n\nimport jinja2\nimport pytest\n\nfrom starlette.applications import Starlette\nfrom starlette.middleware import Middleware\nfrom starlette.middleware.base import BaseHTTPMiddleware, RequestResponseEndpoint\nfrom starlette.requests import Request\nfrom starlette.responses import Response\nfrom starlette.routing import Route\nfrom starlette.templating import Jinja2Templates\nfrom tests.types import TestClientFactory\n\n\ndef test_templates(tmpdir: Path, test_client_factory: TestClientFactory) -> None:\n    path = os.path.join(tmpdir, "index.html")\n    with open(path, "w") as file:\n        file.write("<html>Hello, <a href=\'{{ url_for(\'homepage\') }}\'>world</a></html>")\n\n    async def homepage(request: Request) -> Response:\n        return templates.TemplateResponse(request, "index.html")\n\n    app = Starlette(debug=True, routes=[Route("/", endpoint=homepage)])\n    templates = Jinja2Templates(directory=str(tmpdir))\n\n    client = test_client_factory(app)\n    response = client.get("/")\n    assert response.text == "<html>Hello, <a href=\'http://testserver/\'>world</a></html>"\n    assert response.template.name == "index.html"  # type: ignore\n    assert set(response.context.keys()) == {"request"}  # type: ignore\n\n\ndef test_calls_context_processors(tmp_path: Path, test_client_factory: TestClientFactory) -> None:\n    path = tmp_path / "index.html"\n    path.write_text("<html>Hello {{ username }}</html>")\n\n    async def homepage(request: Request) -> Response:\n        return templates.TemplateResponse(request, "index.html")\n\n    def hello_world_processor(request: Request) -> dict[str, str]:\n        return {"username": "World"}\n\n    app = Starlette(\n        debug=True,\n        routes=[Route("/", endpoint=homepage)],\n    )\n    templates = Jinja2Templates(\n        directory=tmp_path,\n        context_processors=[\n            hello_world_processor,\n        ],\n    )\n\n    client = test_client_factory(app)\n    response = client.get("/")\n    assert response.text == "<html>Hello World</html>"\n    assert response.template.name == "index.html"  # type: ignore\n    assert set(response.context.keys()) == {"request", "username"}  # type: ignore\n\n\ndef test_template_with_middleware(tmpdir: Path, test_client_factory: TestClientFactory) -> None:\n    path = os.path.join(tmpdir, "index.html")\n    with open(path, "w") as file:\n        file.write("<html>Hello, <a href=\'{{ url_for(\'homepage\') }}\'>world</a></html>")\n\n    async def homepage(request: Request) -> Response:\n        return templates.TemplateResponse(request, "index.html")\n\n    class CustomMiddleware(BaseHTTPMiddleware):\n        async def dispatch(self, request: Request, call_next: RequestResponseEndpoint) -> Response:\n            return await call_next(request)\n\n    app = Starlette(\n        debug=True,\n        routes=[Route("/", endpoint=homepage)],\n        middleware=[Middleware(CustomMiddleware)],\n    )\n    templates = Jinja2Templates(directory=str(tmpdir))\n\n    client = test_client_factory(app)\n    response = client.get("/")\n    assert response.text == "<html>Hello, <a href=\'http://testserver/\'>world</a></html>"\n    assert response.template.name == "index.html"  # type: ignore\n    assert set(response.context.keys()) == {"request"}  # type: ignore\n\n\ndef test_templates_with_directories(tmp_path: Path, test_client_factory: TestClientFactory) -> None:\n    dir_a = tmp_path.resolve() / "a"\n    dir_a.mkdir()\n    template_a = dir_a / "template_a.html"\n    template_a.write_text("<html><a href=\'{{ url_for(\'page_a\') }}\'></a> a</html>")\n\n    async def page_a(request: Request) -> Response:\n        return templates.TemplateResponse(request, "template_a.html")\n\n    dir_b = tmp_path.resolve() / "b"\n    dir_b.mkdir()\n    template_b = dir_b / "template_b.html"\n    template_b.write_text("<html><a href=\'{{ url_for(\'page_b\') }}\'></a> b</html>")\n\n    async def page_b(request: Request) -> Response:\n        return templates.TemplateResponse(request, "template_b.html")\n\n    app = Starlette(\n        debug=True,\n        routes=[Route("/a", endpoint=page_a), Route("/b", endpoint=page_b)],\n    )\n    templates = Jinja2Templates(directory=[dir_a, dir_b])\n\n    client = test_client_factory(app)\n    response = client.get("/a")\n    assert response.text == "<html><a href=\'http://testserver/a\'></a> a</html>"\n    assert response.template.name == "template_a.html"  # type: ignore\n    assert set(response.context.keys()) == {"request"}  # type: ignore\n\n    response = client.get("/b")\n    assert response.text == "<html><a href=\'http://testserver/b\'></a> b</html>"\n    assert response.template.name == "template_b.html"  # type: ignore\n    assert set(response.context.keys()) == {"request"}  # type: ignore\n\n\ndef test_templates_require_directory_or_environment() -> None:\n    with pytest.raises(AssertionError, match="either \'directory\' or \'env\' arguments must be passed"):\n        Jinja2Templates()  # type: ignore[call-overload]\n\n\ndef test_templates_require_directory_or_environment_not_both() -> None:\n    with pytest.raises(AssertionError, match="either \'directory\' or \'env\' arguments must be passed"):\n        Jinja2Templates(directory="dir", env=jinja2.Environment())  # type: ignore[call-overload]\n\n\ndef test_templates_with_directory(tmpdir: Path) -> None:\n    path = os.path.join(tmpdir, "index.html")\n    with open(path, "w") as file:\n        file.write("Hello")\n\n    templates = Jinja2Templates(directory=str(tmpdir))\n    template = templates.get_template("index.html")\n    assert template.render({}) == "Hello"\n\n\ndef test_templates_with_environment(tmpdir: Path, test_client_factory: TestClientFactory) -> None:\n    path = os.path.join(tmpdir, "index.html")\n    with open(path, "w") as file:\n        file.write("<html>Hello, <a href=\'{{ url_for(\'homepage\') }}\'>world</a></html>")\n\n    async def homepage(request: Request) -> Response:\n        return templates.TemplateResponse(request, "index.html")\n\n    env = jinja2.Environment(loader=jinja2.FileSystemLoader(str(tmpdir)))\n    app = Starlette(\n        debug=True,\n        routes=[Route("/", endpoint=homepage)],\n    )\n    templates = Jinja2Templates(env=env)\n    client = test_client_factory(app)\n    response = client.get("/")\n    assert response.text == "<html>Hello, <a href=\'http://testserver/\'>world</a></html>"\n    assert response.template.name == "index.html"  # type: ignore\n    assert set(response.context.keys()) == {"request"}  # type: ignore\n',
        }
